import { Dexie, type Table } from 'dexie';

export interface Order {
  id?: number;
  uuid: string; // Globally unique identifier for cloud sync
  orderNo?: string; // New field
  custCode?: string; // New field
  customer: string;
  city: string;
  zipCode?: string; // New field
  material: string;
  qty: number;
  status: string;
  createdAt: number;
  updatedAt: number; // Timestamp for sync resolution
  note?: string;
  attachments?: string[]; // Array of base64 strings
}

export interface Shipment {
  id?: number;
  uuid: string;
  reference: string;
  orderUuids: string[];
  attachments: string[];
  createdAt: number;
  updatedAt: number;
  dispatchDate: number; // Actual date of dispatch/loading
  invoiceNo?: string; // New field
  invoiceDate?: number; // New field (timestamp)
  vehicleNo?: string; // New field
  transporter?: string; // New field
  lrNo?: string; // New field
  note?: string;
}

export interface MasterItem {
  id?: number;
  name: string;
}

export class OrderTrackerDB extends Dexie {
  orders!: Table<Order>;
  shipments!: Table<Shipment>;
  customersMaster!: Table<MasterItem>;
  citiesMaster!: Table<MasterItem>;
  materialsMaster!: Table<MasterItem>;

  constructor() {
    super('OrderTrackerDB');

    // Fix: Explicitly cast 'this' to 'any' to call .version() and bypass TypeScript 
    // inheritance resolution issues that can occur with the Dexie class pattern.
    (this as any).version(10).stores({
      orders: '++id, &uuid, orderNo, custCode, customer, city, material, qty, status, createdAt, updatedAt',
      shipments: '++id, &uuid, reference, invoiceNo, vehicleNo, transporter, lrNo, *orderUuids, createdAt, dispatchDate',
      customersMaster: '++id, &name',
      citiesMaster: '++id, &name',
      materialsMaster: '++id, &name'
    });
  }
}

