/**
 * Manually pushes parsed CSV data (orders) to the Supabase database.
 */
export const importCsvToSupabase = async (data: any[]) => {
  const client = initSupabase();
  if (!client) throw new Error("Cloud Datastore not configured.");

  const payload = data.map(o => ({
    uuid: o.uuid || crypto.randomUUID(),
    order_no: o.orderNo,
    cust_code: o.custCode,
    customer: o.customer,
    city: o.city,
    zip_code: o.zipCode,
    material: o.material,
    qty: Number(o.qty),
    status: o.status || 'Pending',
    note: o.note,
    attachments: typeof o.attachments === 'string' ? JSON.parse(o.attachments) : (o.attachments || []),
    invoice_no: o.invoiceNo,
    invoice_date: o.invoiceDate ? new Date(o.invoiceDate).toISOString() : null,
    vehicle_no: o.vehicleNo,
    transporter: o.transporter,
    lr_no: o.lrNo,
    created_at: o.createdAt ? new Date(o.createdAt).toISOString() : new Date().toISOString(),
    updated_at: new Date().toISOString()
  }));

  const { error } = await client.from('orders').upsert(payload, { onConflict: 'uuid' });
  if (error) throw error;

  return payload.length;
};

import React, { useState, useEffect } from 'react';
import { db } from '../db';
import { exportToCSV, parseCSV } from '../services/csvService';
import { saveSyncConfig, getSyncConfig, clearSupabaseData, importCsvToSupabase } from '../services/syncService';

const Backup: React.FC = () => {
  const [importingLocal, setImportingLocal] = useState(false);
  const [importingCloud, setImportingCloud] = useState(false);
  const [exporting, setExporting] = useState(false);
  const [clearingCloud, setClearingCloud] = useState(false);
  const [clearingLocal, setClearingLocal] = useState(false);

  const [cloudConfig, setCloudConfig] = useState({
    url: '',
    publishableKey: ''
  });

  useEffect(() => {
    const config = getSyncConfig();
    if (config) setCloudConfig(config);
  }, []);

  const handleSaveConfig = () => {
    if (!cloudConfig.url || !cloudConfig.publishableKey) {
      alert("Missing Information: Both Supabase URL and Key are required.");
      return;
    }
    saveSyncConfig(cloudConfig);
    alert("Cloud Credentials Updated.");
  };

  const handleExportLocal = async () => {
    setExporting(true);
    try {
      const orders = await db.orders.toArray();
      if (orders.length === 0) {
        alert("Local database is empty.");
        return;
      }
      exportToCSV(orders, `local_orders_backup_${new Date().toISOString().split('T')[0]}.csv`);
    } catch (err) {
      alert("CSV Export failed.");
    } finally {
      setExporting(false);
    }
  };

  const handleImportLocal = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setImportingLocal(true);
    try {
      const data = await parseCSV(file);
      if (!Array.isArray(data)) throw new Error("Invalid CSV.");

      let count = 0;
      for (const item of data) {
        if (!item.uuid) item.uuid = crypto.randomUUID();
        if (typeof item.attachments === 'string') {
          try { item.attachments = JSON.parse(item.attachments); } catch { item.attachments = []; }
        }
        const existing = await db.orders.where('uuid').equals(item.uuid).first();
        if (existing) {
          await db.orders.update(existing.id!, { ...item, updatedAt: Date.now() });
        } else {
          await db.orders.add({ ...item, updatedAt: Date.now() });
        }
        count++;
      }
      alert(`Import Success: Merged ${count} records into LOCAL storage.`);
    } catch (err: any) {
      alert(`Import Error: ${err.message}`);
    } finally {
      setImportingLocal(false);
      if (e.target) e.target.value = '';
    }
  };

  const handleImportToCloud = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !cloudConfig.url) {
      alert("Please configure Cloud first.");
      return;
    }
    setImportingCloud(true);
    try {
      const data = await parseCSV(file);
      const count = await importCsvToSupabase(data);
      alert(`Cloud Upload Success: ${count} records pushed to Supabase.`);
    } catch (err: any) {
      console.error(err);
      alert(`Cloud Upload Failed: ${err.message}`);
    } finally {
      setImportingCloud(false);
      if (e.target) e.target.value = '';
    }
  };

  const handleWipeCloud = async () => {
    if (!confirm("Permanently ERASE all data from Cloud (Supabase)? Local data will not be affected.")) return;
    setClearingCloud(true);
    try {
      await clearSupabaseData();
      alert("Cloud database cleared.");
    } catch (err: any) {
      alert(`Reset Failed: ${err.message}`);
    } finally {
      setClearingCloud(false);
    }
  };

  const handleWipeLocal = async () => {
    if (!confirm("Permanently ERASE all data from LOCAL device? Cloud data will not be affected.")) return;
    setClearingLocal(true);
    try {
      await Promise.all([
        db.orders.clear(),
        db.customersMaster.clear(),
        db.citiesMaster.clear(),
        db.materialsMaster.clear()
      ]);
      alert("Local storage cleared.");
    } catch (err: any) {
      alert(`Wipe Failed: ${err.message}`);
    } finally {
      setClearingLocal(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto space-y-12 animate-in fade-in duration-700 pb-24 px-4">
      <header className="text-center">
        <h2 className="text-4xl font-black text-gray-900 tracking-tighter uppercase">Storage Management</h2>
        <p className="text-gray-400 font-bold uppercase text-[10px] tracking-[0.3em] mt-2">Manage Local and Cloud Data independently</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
        {/* Local Storage Section */}
        <section className="bg-white p-8 md:p-10 rounded-[3rem] border border-gray-100 shadow-xl space-y-8">
           <div className="flex items-center gap-4">
              <div className="w-14 h-14 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center justify-center shadow-inner">
                <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}><path d="M5 12h14M5 12a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v4a2 2 0 01-2 2M5 12a2 2 0 00-2 2v4a2 2 0 002 2h14a2 2 0 002-2v-4a2 2 0 00-2-2m-2-4h.01M17 16h.01" /></svg>
              </div>
              <div>
                <h3 className="text-2xl font-black text-gray-900 uppercase tracking-tighter">Local Control</h3>
                <p className="text-[10px] text-emerald-600 font-black uppercase tracking-widest">Standalone Device Storage</p>
              </div>
           </div>

           <div className="grid grid-cols-1 gap-4">
              <button 
                onClick={handleExportLocal}
                disabled={exporting}
                className="flex items-center justify-between p-6 bg-emerald-50 text-emerald-700 rounded-3xl hover:bg-emerald-600 hover:text-white transition-all group font-black uppercase tracking-widest text-xs"
              >
                <span>Export Local CSV</span>
                <svg className="w-5 h-5 group-hover:translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M12 16V10m0 0l-3 3m3-3l3 3m2-8H7a2 2 0 00-2 2v14a2 2 0 002 2h10a2 2 0 002-2V9" /></svg>
              </button>

              <label className="flex items-center justify-between p-6 bg-white border-2 border-dashed border-emerald-100 text-emerald-600 rounded-3xl hover:bg-emerald-50 cursor-pointer transition-all font-black uppercase tracking-widest text-xs">
