      alert(`Cloud Upload Success: ${count} records pushed to Supabase.`);
    } catch (err: any) {
      console.error(err);
      alert(`Cloud Upload Failed: ${err.message}`);
    } finally {
      setImportingCloud(false);
      if (e.target) e.target.value = '';
    }
  };

  const handleWipeCloud = async () => {
    if (!confirm("Permanently ERASE all data from Cloud (Supabase)? Local data will not be affected.")) return;
    setClearingCloud(true);
    try {
      await clearSupabaseData();
      alert("Cloud database cleared.");
    } catch (err: any) {
      alert(`Reset Failed: ${err.message}`);
    } finally {
      setClearingCloud(false);
    }
  };

  const handleWipeLocal = async () => {
    if (!confirm("Permanently ERASE all data from LOCAL device? Cloud data will not be affected.")) return;
    setClearingLocal(true);
    try {
      await Promise.all([
        db.orders.clear(),
        db.shipments.clear(),
        db.customersMaster.clear(),
        db.citiesMaster.clear(),
        db.materialsMaster.clear()
      ]);
      alert("Local storage cleared.");
    } catch (err: any) {
      alert(`Wipe Failed: ${err.message}`);
    } finally {
      setClearingLocal(false);
    }
  };

