           <div className="flex items-center gap-4">
              <div className="w-14 h-14 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center justify-center shadow-inner">
                <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}><path d="M5 12h14M5 12a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v4a2 2 0 01-2 2M5 12a2 2 0 00-2 2v4a2 2 0 002 2h14a2 2 0 002-2v-4a2 2 0 00-2-2m-2-4h.01M17 16h.01" /></svg>
              </div>
              <div>
                <h3 className="text-2xl font-black text-gray-900 uppercase tracking-tighter">Offline Data</h3>
                <p className="text-[10px] text-emerald-600 font-black uppercase tracking-widest">Device-Only Storage</p>
              </div>
           </div>

           <div className="grid grid-cols-1 gap-4">
              <button 
                onClick={handleExportLocal}
                disabled={exportingLocal}
                className="flex items-center justify-between p-6 bg-emerald-50 text-emerald-700 rounded-3xl hover:bg-emerald-600 hover:text-white transition-all group font-black uppercase tracking-widest text-xs"
              >
                <span>Export Offline CSV</span>
                <svg className="w-5 h-5 group-hover:translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M12 16V10m0 0l-3 3m3-3l3 3m2-8H7a2 2 0 00-2 2v14a2 2 0 002 2h10a2 2 0 002-2V9" /></svg>
              </button>

              <label className="flex items-center justify-between p-6 bg-white border-2 border-dashed border-emerald-100 text-emerald-600 rounded-3xl hover:bg-emerald-50 cursor-pointer transition-all font-black uppercase tracking-widest text-xs">
                <input type="file" accept=".csv" className="hidden" onChange={handleImportLocal} disabled={importingLocal} />
                <span>{importingLocal ? 'Importing...' : 'Import CSV to Local'}</span>
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5" /></svg>
              </label>

              <button 
