/**
 * Manually pushes parsed CSV data (orders) to the Supabase database.
 * Uses 'upsert' on 'uuid' to ensure that duplicate records are updated instead of duplicated.
 */
export const importCsvToSupabase = async (data: any[]) => {
  const client = initSupabase();
  if (!client) throw new Error("Cloud Datastore not configured.");

  const payload = data.map(o => {
    // Helper to parse dates from various formats (timestamps or strings)
    const parseDate = (val: any) => {
      if (!val) return null;
      const d = new Date(isNaN(val) ? val : Number(val));
      return d.getTime() ? d.toISOString() : null;
    };

    // Helper to safely handle attachments
    let parsedAttachments = [];
    if (o.attachments) {
      if (Array.isArray(o.attachments)) {
        parsedAttachments = o.attachments;
      } else if (typeof o.attachments === 'string') {
        try {
          const p = JSON.parse(o.attachments);
          if (Array.isArray(p)) parsedAttachments = p;
        } catch (e) {
          // Fallback if it's a single string URL or invalid JSON
          parsedAttachments = [o.attachments];
        }
      }
    }

    return {
      uuid: o.uuid || crypto.randomUUID(),
      order_no: String(o.orderNo || o.order_no || ''),
      cust_code: String(o.custCode || o.cust_code || ''),
      customer: String(o.customer || 'Unknown'),
      city: String(o.city || 'Unknown'),
      zip_code: String(o.zipCode || o.zip_code || ''),
      material: String(o.material || 'N/A'),
      qty: Number(o.qty || 0),
      status: o.status || 'Pending',
      note: o.note || '',
      attachments: parsedAttachments,
      invoice_no: o.invoiceNo || o.invoice_no || '',
      invoice_date: parseDate(o.invoiceDate || o.invoice_date),
      vehicle_no: o.vehicleNo || o.vehicle_no || '',
      transporter: o.transporter || '',
      lr_no: o.lrNo || o.lr_no || '',
      created_at: parseDate(o.createdAt || o.created_at) || new Date().toISOString(),
      updated_at: new Date().toISOString()
    };
  });

  // Batch upsert to Supabase targeting the uuid column
  const { error } = await client.from('orders').upsert(payload, { onConflict: 'uuid' });
  if (error) throw error;

  return payload.length;
};

