 * If a row in the CSV contains a UUID that already exists in the cloud,
 * every field in that cloud record will be updated to match the CSV payload.
 */
export const importCsvToSupabase = async (data: any[]) => {
  const client = initSupabase();
  if (!client) throw new Error("Cloud Datastore not configured.");

