      vehicle_no: o.vehicleNo || o.vehicle_no || '',
      transporter: o.transporter || '',
      lr_no: o.lrNo || o.lr_no || '',
      // Map timestamps: keep original creation date, update current sync time
      created_at: parseToIso(o.createdAt || o.created_at) || nowIso,
      updated_at: nowIso
    };
  });

  // Upsert with 'onConflict: uuid' ensures matching records are updated field-for-field.
  const { error } = await client.from('orders').upsert(payload, { 
    onConflict: 'uuid',
    ignoreDuplicates: false // Explicitly allow updates to existing records
  });

  if (error) {
