export default Backup;

import { Dexie, type Table } from 'dexie';

export interface Order {
  id?: number;
  uuid: string;
  orderNo?: string;
  orderDate: number; // Business Order Date
  custCode?: string;
  customer: string;
  city: string;
  zipCode?: string;
  material: string;
  qty: number;
  status: string;
  createdAt: number; // Technical Creation Time
  updatedAt: number; // Technical Update Time
  note?: string;
  attachments?: string[];
  invoiceNo?: string;
  invoiceDate?: number;
  vehicleNo?: string;
  transporter?: string;
  lrNo?: string;
}

export interface Shipment {
  id?: number;
  uuid: string;
  reference: string;
  orderUuids: string[];
  attachments: string[];
  createdAt: number;
  updatedAt: number;
  dispatchDate: number;
  note?: string;
}

export interface MasterItem {
  id?: number;
  name: string;
}

export class OrderTrackerDB extends Dexie {
  orders!: Table<Order>;
  shipments!: Table<Shipment>;
  customersMaster!: Table<MasterItem>;
  citiesMaster!: Table<MasterItem>;
  materialsMaster!: Table<MasterItem>;

  constructor() {
    super('OrderTrackerDB');

    (this as any).version(12).stores({
      orders: '++id, &uuid, orderNo, orderDate, custCode, customer, city, material, qty, status, invoiceNo, vehicleNo, lrNo, createdAt, updatedAt',
      shipments: '++id, &uuid, reference, *orderUuids, createdAt, dispatchDate',
      customersMaster: '++id, &name',
      citiesMaster: '++id, &name',
      materialsMaster: '++id, &name'
    });
  }
}

export const db = new OrderTrackerDB();

import { db, Order } from '../db';
import { initSupabase } from './syncService';
import { StorageMode } from '../types';

export const getOrders = async (mode: StorageMode): Promise<Order[]> => {
  if (mode === StorageMode.OFFLINE) {
    return db.orders.reverse().sortBy('orderDate');
  } else {
    const supabase = initSupabase();
    if (!supabase) throw new Error("Remote access not configured");

    const { data, error } = await supabase
      .from('orders')
      .select('*')
      .order('order_date', { ascending: false });

    if (error) throw error;

    return (data || []).map(remote => ({
      id: remote.id,
      uuid: remote.uuid,
      orderNo: remote.order_no,
      orderDate: new Date(remote.order_date).getTime(),
      custCode: remote.cust_code,
      customer: remote.customer,
      city: remote.city,
      zipCode: remote.zip_code,
      material: remote.material,
      qty: remote.qty,
      status: remote.status,
      note: remote.note,
      attachments: remote.attachments,
      createdAt: new Date(remote.created_at).getTime(),
      updatedAt: new Date(remote.updated_at).getTime(),
      invoiceNo: remote.invoice_no,
      invoiceDate: remote.invoice_date ? new Date(remote.invoice_date).getTime() : undefined,
      vehicleNo: remote.vehicle_no,
      transporter: remote.transporter,
      lrNo: remote.lr_no
    }));
  }
};

export const saveOrder = async (mode: StorageMode, order: Order, editId?: number | null) => {
  if (mode === StorageMode.OFFLINE) {
    if (editId) {
      return await db.orders.update(editId, order as any);
    } else {
      return await db.orders.add(order);
    }
  } else {
    const supabase = initSupabase();
    if (!supabase) throw new Error("Remote access not configured");

    const payload = {
      uuid: order.uuid,
      order_no: order.orderNo,
      order_date: new Date(order.orderDate).toISOString().split('T')[0],
      cust_code: order.custCode,
      customer: order.customer,
      city: order.city,
      zip_code: order.zipCode,
      material: order.material,
      qty: order.qty,
      status: order.status,
      note: order.note,
      attachments: order.attachments,
      invoice_no: order.invoiceNo,
      invoice_date: order.invoiceDate ? new Date(order.invoiceDate).toISOString().split('T')[0] : null,
      vehicle_no: order.vehicleNo,
      transporter: order.transporter,
      lr_no: order.lrNo,
      created_at: new Date(order.createdAt).toISOString(),
      updated_at: new Date().toISOString()
    };

    const { error } = await supabase
      .from('orders')
      .upsert(payload, { onConflict: 'uuid' });

    if (error) throw error;
  }
};

export const deleteOrder = async (mode: StorageMode, id: number, uuid: string) => {
  if (mode === StorageMode.OFFLINE) {
    return await db.orders.delete(id);
  } else {
    const supabase = initSupabase();
    if (!supabase) throw new Error("Remote access not configured");
    const { error } = await supabase
      .from('orders')
      .delete()
      .eq('uuid', uuid);
    if (error) throw error;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { db, Order } from '../db';
import AutocompleteInput from './AutocompleteInput';
import { StorageMode } from '../types';
import { saveOrder, getOrders } from '../services/orderService';
import { initSupabase } from '../services/syncService';

interface Props {
  mode: StorageMode;
  editId?: number | null;
  onSuccess: () => void;
  onCancel: () => void;
}

const STATUS_OPTIONS = ['Pending', 'Processing', 'Shipped', 'Delivered', 'Cancelled'];

const AddOrder: React.FC<Props> = ({ mode, editId, onSuccess, onCancel }) => {
  const [formData, setFormData] = useState<{
    uuid: string;
    orderNo: string;
    orderDate: string;
    custCode: string;
    customer: string;
    city: string;
    zipCode: string;
    material: string;
    qty: number;
    status: string;
    note: string;
    attachments: string[];
    // Technical creation date hidden from form
    invoiceNo: string;
    invoiceDate: string;
    vehicleNo: string;
    transporter: string;
    lrNo: string;
  }>({
    uuid: crypto.randomUUID(),
    orderNo: '',
    orderDate: new Date().toISOString().split('T')[0],
    custCode: '',
    customer: '',
    city: '',
    zipCode: '',
    material: '',
    qty: 0,
    status: 'Pending',
    note: '',
    attachments: [],
    invoiceNo: '',
    invoiceDate: '',
    vehicleNo: '',
    transporter: '',
    lrNo: ''
  });

  const [isProcessingImages, setIsProcessingImages] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [options, setOptions] = useState<{ customers: string[], cities: string[], materials: string[] }>({
    customers: [],
    cities: [],
    materials: []
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const loadOptions = async () => {
      if (mode === StorageMode.OFFLINE) {
        const orders = await db.orders.toArray();
        const masterCustomers = await db.customersMaster.toArray();
        const masterCities = await db.citiesMaster.toArray();
        const masterMaterials = await db.materialsMaster.toArray();

        const distinct = (arr: string[]) => Array.from(new Set(arr.filter(Boolean).map(s => s.trim()))).sort();

        setOptions({
          customers: distinct([...orders.map(o => o.customer), ...masterCustomers.map(c => c.name)]),
          cities: distinct([...orders.map(o => o.city), ...masterCities.map(c => c.name)]),
          materials: distinct([...orders.map(o => o.material), ...masterMaterials.map(m => m.name)]),
        });
      } else {
        const supabase = initSupabase();
        if (!supabase) return;

        const [ordersRes, customersRes, citiesRes, materialsRes] = await Promise.all([
           supabase.from('orders').select('customer, city, material'),
           supabase.from('customersMaster').select('name'),
           supabase.from('citiesMaster').select('name'),
           supabase.from('materialsMaster').select('name')
        ]);

        const distinct = (arr: string[]) => Array.from(new Set(arr.filter(Boolean).map(s => s.trim()))).sort();

        setOptions({
          customers: distinct([...(ordersRes.data?.map(o => o.customer) || []), ...(customersRes.data?.map(c => c.name) || [])]),
          cities: distinct([...(ordersRes.data?.map(o => o.city) || []), ...(citiesRes.data?.map(c => c.name) || [])]),
          materials: distinct([...(ordersRes.data?.map(o => o.material) || []), ...(materialsRes.data?.map(m => m.name) || [])]),
        });
      }
    };
    loadOptions();

    if (editId) {
      if (mode === StorageMode.OFFLINE) {
        db.orders.get(editId).then(order => {
          if (order) {
            setFormData({
              uuid: order.uuid || crypto.randomUUID(), 
              orderNo: order.orderNo || '',
              orderDate: new Date(order.orderDate).toISOString().split('T')[0],
              custCode: order.custCode || '',
              customer: order.customer,
              city: order.city,
              zipCode: order.zipCode || '',
              material: order.material,
              qty: order.qty,
              status: order.status || 'Pending',
              note: order.note || '',
              attachments: order.attachments || [],
              invoiceNo: order.invoiceNo || '',
              invoiceDate: order.invoiceDate ? new Date(order.invoiceDate).toISOString().split('T')[0] : '',
              vehicleNo: order.vehicleNo || '',
              transporter: order.transporter || '',
              lrNo: order.lrNo || ''
            });
          }
        });
      } else {
        const supabase = initSupabase();
        if (supabase) {
           supabase.from('orders').select('*').eq('id', editId).single().then(({ data }) => {
             if (data) {
               setFormData({
                 uuid: data.uuid,
                 orderNo: data.order_no || '',
                 orderDate: data.order_date || new Date(data.created_at).toISOString().split('T')[0],
                 custCode: data.cust_code || '',
                 customer: data.customer,
                 city: data.city,
                 zipCode: data.zip_code || '',
                 material: data.material,
                 qty: data.qty,
                 status: data.status,
                 note: data.note,
                 attachments: data.attachments || [],
                 invoiceNo: data.invoice_no || '',
                 invoiceDate: data.invoice_date ? new Date(data.invoice_date).toISOString().split('T')[0] : '',
                 vehicleNo: data.vehicle_no || '',
                 transporter: data.transporter || '',
                 lrNo: data.lr_no || ''
               });
             }
           });
        }
      }
    }
  }, [editId, mode]);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    setIsProcessingImages(true);
    try {
      const readFileAsDataURL = (file: File): Promise<string> => {
        return new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = () => resolve(reader.result as string);
          reader.onerror = (error) => reject(error);
          reader.readAsDataURL(file);
        });
      };

      const downscaleImage = (dataUrl: string, maxWidth = 1200, quality = 0.7): Promise<string> => {
        return new Promise((resolve) => {
          const img = new Image();
          img.src = dataUrl;
          img.onload = () => {
            const canvas = document.createElement('canvas');
            let width = img.width;
            let height = img.height;
            if (width > maxWidth) {
              height = (maxWidth / width) * height;
              width = maxWidth;
            }
            canvas.width = width;
            canvas.height = height;
            const ctx = canvas.getContext('2d');
            ctx?.drawImage(img, 0, 0, width, height);
            resolve(canvas.toDataURL('image/jpeg', quality));
          };
          img.onerror = () => resolve(dataUrl);
        });
      };

      const rawDataUrls = await Promise.all(
        Array.from(files).map(file => readFileAsDataURL(file as File))
      );
      const optimizedAttachments = await Promise.all(
        rawDataUrls.map(url => downscaleImage(url))
      );
      setFormData(prev => ({
        ...prev,
        attachments: [...prev.attachments, ...optimizedAttachments]
      }));
    } catch (err) {
      console.error("Error reading files:", err);
    } finally {
      setIsProcessingImages(false);
      if (e.target) e.target.value = '';
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isSaving) return;

    const { 
      uuid, orderNo, orderDate, custCode, customer, city, zipCode, material, qty, status, note, attachments,
      invoiceNo, invoiceDate, vehicleNo, transporter, lrNo
    } = formData;

    if (!customer.trim() || !city.trim() || !material.trim() || qty <= 0 || !orderDate) {
      alert("Please fill all required fields.");
      return;
    }

    setIsSaving(true);
    const now = Date.now();
    const finalOrderDate = new Date(`${orderDate}T12:00:00`).getTime();
    const finalInvoiceDate = invoiceDate ? new Date(`${invoiceDate}T12:00:00`).getTime() : undefined;

    const orderData: Order = {
      uuid: uuid || crypto.randomUUID(),
      orderNo: orderNo.trim(),
      orderDate: finalOrderDate,
      custCode: custCode.trim(),
      customer: customer.trim(),
      city: city.trim(),
      zipCode: zipCode.trim(),
      material: material.trim(),
      qty: Number(qty),
      status: status,
      note: note.trim(),
      attachments,
      createdAt: editId ? (await db.orders.get(editId))?.createdAt || now : now,
      updatedAt: now,
      invoiceNo: invoiceNo.trim(),
      invoiceDate: finalInvoiceDate,
      vehicleNo: vehicleNo.trim(),
      transporter: transporter.trim(),
      lrNo: lrNo.trim()
    };

    try {
      await saveOrder(mode, orderData, editId);
      onSuccess();
    } catch (err: any) {
      console.error(err);
      alert(`Save failed: ${err.message}`);
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="max-w-xl mx-auto">
      <div className="bg-white rounded-[2.5rem] shadow-2xl p-8 border border-gray-100">
        <header className="mb-8 flex justify-between items-start">
          <div>
            <h2 className="text-3xl font-black text-gray-900 leading-tight uppercase tracking-tighter">
              {editId ? 'Edit Order' : 'Add Order'}
            </h2>
            <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest mt-1">Environment: {mode === StorageMode.ONLINE ? 'Cloud Live' : 'Standalone Local'}</p>
          </div>
          <div className={`w-3.5 h-3.5 rounded-full ${mode === StorageMode.ONLINE ? 'bg-blue-600 animate-pulse shadow-[0_0_12px_rgba(37,99,235,0.4)]' : 'bg-indigo-50 shadow-[0_0_12px_rgba(79,70,229,0.3)]'}`}></div>
        </header>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
            <div>
              <label className="block text-xs font-black text-gray-500 mb-2 uppercase tracking-widest">Order No.</label>
              <input
                type="text"
                value={formData.orderNo}
                onChange={(e) => setFormData({ ...formData, orderNo: e.target.value })}
                className="w-full px-5 py-3.5 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-indigo-500 shadow-inner font-bold"
                placeholder="Ex: ORD-5502"
              />
            </div>
            <div>
              <label className="block text-xs font-black text-gray-500 mb-2 uppercase tracking-widest">Order Date</label>
              <input
                type="date"
                value={formData.orderDate}
                onChange={(e) => setFormData({ ...formData, orderDate: e.target.value })}
                className="w-full px-5 py-3.5 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-indigo-500 shadow-inner font-bold outline-none"
                required
              />
            </div>
          </div>

          <div className="grid grid-cols-1 gap-6">
            <AutocompleteInput
              label="Customer Name"
              value={formData.customer}
              onChange={(val) => setFormData({ ...formData, customer: val })}
              options={options.customers}
              placeholder="Search or enter client..."
              required
            />
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
            <div>
              <label className="block text-xs font-black text-gray-500 mb-2 uppercase tracking-widest">Cust Code</label>
              <input
                type="text"
                value={formData.custCode}
                onChange={(e) => setFormData({ ...formData, custCode: e.target.value })}
                className="w-full px-5 py-3.5 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-indigo-500 shadow-inner font-bold"
                placeholder="Ex: C-101"
              />
            </div>
            <div>
              <label className="block text-xs font-black text-gray-500 mb-2 uppercase tracking-widest">Zip Code</label>
              <input
                type="text"
                value={formData.zipCode}
                onChange={(e) => setFormData({ ...formData, zipCode: e.target.value })}
                className="w-full px-5 py-3.5 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-indigo-500 shadow-inner font-bold"
                placeholder="Ex: 400001"
              />
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
            <AutocompleteInput
              label="Destination City"
              value={formData.city}
              onChange={(val) => setFormData({ ...formData, city: val })}
              options={options.cities}
              placeholder="Select city..."
              required
            />
            <AutocompleteInput
              label="Material"
              value={formData.material}
              onChange={(val) => setFormData({ ...formData, material: val })}
              options={options.materials}
              placeholder="Search material..."
              required
            />
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
            <div>
              <label className="block text-xs font-black text-gray-500 mb-2 uppercase tracking-widest">Quantity</label>
              <input
                type="number"
                value={formData.qty || ''}
                onChange={(e) => setFormData({ ...formData, qty: Number(e.target.value) })}
                className="w-full px-5 py-3.5 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-indigo-500 shadow-inner font-black text-lg"
                required
                min="1"
              />
            </div>
            <div>
              <label className="block text-xs font-black text-gray-500 mb-2 uppercase tracking-widest">Order Status</label>
              <select
                value={formData.status}
                onChange={(e) => setFormData({ ...formData, status: e.target.value })}
                className="w-full px-5 py-3.5 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-indigo-500 shadow-inner font-bold cursor-pointer"
              >
                {STATUS_OPTIONS.map(opt => <option key={opt} value={opt}>{opt}</option>)}
              </select>
            </div>
          </div>

          {/* Logistics Section */}
          <div className="p-6 bg-blue-50/40 rounded-[2rem] border border-blue-100 space-y-4">
             <h3 className="text-xs font-black text-blue-600 uppercase tracking-[0.2em] mb-4">Logistics & Shipping</h3>
             <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                   <label className="block text-[9px] font-black text-gray-400 uppercase tracking-widest mb-1.5 ml-1">Invoice Number</label>
                   <input type="text" value={formData.invoiceNo} onChange={e => setFormData({...formData, invoiceNo: e.target.value})} className="w-full px-4 py-2.5 bg-white border-none rounded-xl shadow-sm font-bold text-sm" placeholder="INV-001" />
                </div>
                <div>
                   <label className="block text-[9px] font-black text-gray-400 uppercase tracking-widest mb-1.5 ml-1">Invoice Date</label>
                   <input type="date" value={formData.invoiceDate} onChange={e => setFormData({...formData, invoiceDate: e.target.value})} className="w-full px-4 py-2.5 bg-white border-none rounded-xl shadow-sm font-bold text-sm" />
                </div>
                <div>
                   <label className="block text-[9px] font-black text-gray-400 uppercase tracking-widest mb-1.5 ml-1">Vehicle Number</label>
                   <input type="text" value={formData.vehicleNo} onChange={e => setFormData({...formData, vehicleNo: e.target.value})} className="w-full px-4 py-2.5 bg-white border-none rounded-xl shadow-sm font-bold text-sm" placeholder="MH-01-AB-1234" />
                </div>
                <div>
                   <label className="block text-[9px] font-black text-gray-400 uppercase tracking-widest mb-1.5 ml-1">Transporter</label>
                   <input type="text" value={formData.transporter} onChange={e => setFormData({...formData, transporter: e.target.value})} className="w-full px-4 py-2.5 bg-white border-none rounded-xl shadow-sm font-bold text-sm" placeholder="Blue Dart" />
                </div>
                <div className="sm:col-span-2">
                   <label className="block text-[9px] font-black text-gray-400 uppercase tracking-widest mb-1.5 ml-1">LR / Reference Number</label>
                   <input type="text" value={formData.lrNo} onChange={e => setFormData({...formData, lrNo: e.target.value})} className="w-full px-4 py-2.5 bg-white border-none rounded-xl shadow-sm font-bold text-sm" placeholder="LR-88991122" />
                </div>
             </div>
          </div>

          <div>
            <label className="block text-xs font-black text-gray-500 mb-3 uppercase tracking-widest">Attachments</label>
            <div className="grid grid-cols-4 gap-3">
              {formData.attachments.map((src, idx) => (
                <div key={idx} className="relative aspect-square rounded-2xl overflow-hidden border-2 border-white shadow-md group">
                  <img src={src} className="w-full h-full object-cover" alt="attachment" />
                  <button 
                    type="button"
                    onClick={() => setFormData(p => ({ ...p, attachments: p.attachments.filter((_, i) => i !== idx) }))}
                    className="absolute top-1.5 right-1.5 bg-red-500 text-white p-1.5 rounded-full opacity-0 group-hover:opacity-100 transition-opacity shadow-lg"
                  >
                    <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M6 18L18 6M6 6l12 12" /></svg>
                  </button>
                </div>
              ))}
              <button
                type="button"
                onClick={() => fileInputRef.current?.click()}
                disabled={isProcessingImages}
                className="aspect-square rounded-2xl border-2 border-dashed border-gray-200 text-gray-400 hover:bg-indigo-50 hover:border-indigo-200 hover:text-indigo-500 flex flex-col items-center justify-center disabled:opacity-50 transition-all shadow-inner"
              >
                {isProcessingImages ? (
                   <div className="w-6 h-6 border-3 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
                ) : (
                   <>
                    <svg className="w-8 h-8 mb-1" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M12 4v16m8-8H4" strokeWidth={2.5} /></svg>
                    <span className="text-[8px] font-black uppercase">Attach</span>
                   </>
                )}
              </button>
            </div>
            <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept="image/*" multiple />
          </div>
          <div>
             <label className="block text-xs font-black text-gray-500 mb-2 uppercase tracking-widest">Operational Notes</label>
             <textarea
                value={formData.note}
                onChange={(e) => setFormData({ ...formData, note: e.target.value })}
                className="w-full px-5 py-4 bg-gray-50 border-none rounded-[1.5rem] focus:ring-2 focus:ring-indigo-500 shadow-inner min-h-[100px] font-medium"
                placeholder="Internal memo..."
              />
          </div>
          <div className="flex gap-4 pt-4">
            <button 
              type="submit" 
              disabled={isSaving}
              className={`flex-[2] text-white font-black py-5 rounded-2xl shadow-2xl transition-all active:scale-95 disabled:opacity-50 uppercase tracking-widest text-sm ${mode === StorageMode.ONLINE ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-200' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100'}`}
            >
              {isSaving ? 'Processing...' : (editId ? 'Commit Changes' : 'Save Order')}
            </button>
            <button type="button" onClick={onCancel} className="flex-1 bg-gray-100 text-gray-500 font-black py-5 rounded-2xl hover:bg-gray-200 transition-colors uppercase tracking-widest text-xs">Cancel</button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default AddOrder;

import React, { useState, useEffect } from 'react';
import { db, Order, Shipment } from '../db';
import { exportToCSV, parseCSV } from '../services/csvService';
import { saveSyncConfig, getSyncConfig, clearSupabaseData, importCsvToSupabase, importShipmentsCsvToSupabase, initSupabase } from '../services/syncService';
import { getOrders } from '../services/orderService';
import { getShipments } from '../services/shipmentService';
import { StorageMode } from '../types';

const Backup: React.FC = () => {
  const [importingLocal, setImportingLocal] = useState(false);
  const [importingCloudOrders, setImportingCloudOrders] = useState(false);
  const [importingCloudShipments, setImportingCloudShipments] = useState(false);
  const [exportingLocal, setExportingLocal] = useState(false);
  const [exportingCloud, setExportingCloud] = useState(false);
  const [clearingCloud, setClearingCloud] = useState(false);
  const [clearingLocal, setClearingLocal] = useState(false);
  const [showSql, setShowSql] = useState(false);

  const [cloudConfig, setCloudConfig] = useState({
    url: '',
    publishableKey: ''
  });

  useEffect(() => {
    const config = getSyncConfig();
    if (config) setCloudConfig(config);
  }, []);

  const handleSaveConfig = () => {
    if (!cloudConfig.url || !cloudConfig.publishableKey) {
      alert("Missing Information: Both Supabase URL and Key are required.");
      return;
    }
    saveSyncConfig(cloudConfig);
    alert("Cloud Credentials Updated.");
  };

  const handleExportLocal = async (type: 'orders' | 'shipments') => {
    setExportingLocal(true);
    try {
      const data = type === 'orders' ? await db.orders.toArray() : await db.shipments.toArray();
      if (data.length === 0) {
        alert(`${type} database is empty.`);
        return;
      }
      exportToCSV(data, `local_${type}_backup_${new Date().toISOString().split('T')[0]}.csv`);
    } catch (err) {
      alert("CSV Export failed.");
    } finally {
      setExportingLocal(false);
    }
  };

  const handleExportCloud = async (type: 'orders' | 'shipments') => {
    const client = initSupabase();
    if (!client) {
      alert("Please configure Cloud credentials first.");
      return;
    }
    setExportingCloud(true);
    try {
      const data = type === 'orders' ? await getOrders(StorageMode.ONLINE) : await getShipments(StorageMode.ONLINE);
      if (data.length === 0) {
        alert(`No ${type} found in the cloud database.`);
        return;
      }
      exportToCSV(data, `cloud_${type}_export_${new Date().toISOString().split('T')[0]}.csv`);
    } catch (err: any) {
      alert(`Cloud Export failed: ${err.message}`);
    } finally {
      setExportingCloud(false);
    }
  };

  const handleImportLocal = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setImportingLocal(true);
    try {
      const data = await parseCSV(file);
      if (!Array.isArray(data)) throw new Error("Invalid CSV format.");

      let count = 0;
      for (const item of data) {
        const isShipment = !!(item.orderUuids || item.order_uuids || item.reference);
        const targetTable = isShipment ? db.shipments : db.orders;
        if (!item.uuid) item.uuid = crypto.randomUUID();

        // Normalize column names from CSV to logic fields
        if (!item.orderDate && item.order_date) item.orderDate = item.order_date;
        if (!item.orderDate && item.created_at) item.orderDate = item.created_at;

        if (typeof item.attachments === 'string') {
          try { item.attachments = JSON.parse(item.attachments); } catch { item.attachments = []; }
        }
        if (isShipment && typeof (item.orderUuids || item.order_uuids) === 'string') {
           const raw = item.orderUuids || item.order_uuids;
           try { item.orderUuids = JSON.parse(raw); } catch { item.orderUuids = raw.split(';').map((u: string) => u.trim()); }
        }
        const existing = await targetTable.where('uuid').equals(item.uuid).first();
        if (existing) {
          await targetTable.update((existing as any).id!, { ...item, updatedAt: Date.now() });
        } else {
          await targetTable.add({ ...item, createdAt: Date.now(), updatedAt: Date.now() } as any);
        }
        count++;
      }
      alert(`Local Import Success: Merged ${count} records.`);
    } catch (err: any) {
      alert(`Import Error: ${err.message}`);
    } finally {
      setImportingLocal(false);
      if (e.target) e.target.value = '';
    }
  };

  const handleImportToCloud = async (e: React.ChangeEvent<HTMLInputElement>, type: 'orders' | 'shipments') => {
    const file = e.target.files?.[0];
    if (!file || !cloudConfig.url) {
      alert("Please configure Cloud credentials first.");
      return;
    }
    type === 'orders' ? setImportingCloudOrders(true) : setImportingCloudShipments(true);
    try {
      const data = await parseCSV(file);
