               <select value={filterMaterial} onChange={(e) => setFilterMaterial(e.target.value)} className="px-4 py-2.5 bg-slate-50 border-none rounded-xl text-[11px] font-bold outline-none shadow-sm focus:bg-white focus:ring-1 focus:ring-indigo-100/50">
