                    </div>
                  </div>
                  <div className="bg-slate-50 rounded-2xl p-3.5 text-center min-w-[75px] shadow-sm border border-slate-100 group-hover:bg-indigo-600 group-hover:border-indigo-600 transition-all duration-500">
                    <span className="block text-[8px] text-slate-400 font-black uppercase tracking-widest group-hover:text-white/70">Quantity</span>
                    <span className="block text-2xl font-black text-slate-900 leading-none mt-1 group-hover:text-white">{order.qty}</span>
