                  <div className="flex items-center gap-3 group/item">
                    <div className="w-9 h-9 rounded-2xl bg-blue-50 flex items-center justify-center text-blue-500 group-hover/item:bg-blue-600 group-hover/item:text-white transition-all">
                      <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4" /></svg>
                    </div>
                    <div>
                      <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest leading-none mb-1">Product</p>
                      <span className="text-xs font-bold text-slate-700 uppercase">{order.material}</span>
                    </div>
                  </div>

                  {(order.vehicleNo || order.lrNo) && (
                    <div className="pt-4 border-t border-slate-50/80 grid grid-cols-2 gap-3">
                       {order.vehicleNo && (
                         <div className="flex flex-col p-2.5 bg-slate-50/50 rounded-xl border border-transparent hover:border-indigo-100 transition-all">
                            <p className="text-[7px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1">Vehicle</p>
                            <span className="text-[10px] font-black text-indigo-600 truncate">{order.vehicleNo}</span>
                         </div>
                       )}
                       {order.lrNo && (
                         <div className="flex flex-col p-2.5 bg-slate-50/50 rounded-xl border border-transparent hover:border-indigo-100 transition-all">
                            <p className="text-[7px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1">LR Number</p>
                            <span className="text-[10px] font-black text-indigo-600 truncate">{order.lrNo}</span>
                         </div>
                       )}
                    </div>
                  )}
               </div>

               {/* Image Attachments */}
               {order.attachments && order.attachments.length > 0 && (
                 <div className="flex gap-2.5 mb-6 overflow-x-auto no-scrollbar py-1">
                    {order.attachments.map((img, i) => (
                       <div key={i} onClick={(e) => { e.stopPropagation(); setGalleryState({ images: order.attachments!, index: i }); }} className="w-14 h-14 rounded-2xl overflow-hidden border-2 border-white shadow-md flex-shrink-0 cursor-zoom-in hover:scale-110 transition-transform active:scale-95 duration-300">
                          <img src={img} className="w-full h-full object-cover" alt="proof" loading="lazy" />
                       </div>
                    ))}
                    {order.attachments.length > 4 && (
                      <div className="w-14 h-14 rounded-2xl bg-slate-50 flex items-center justify-center text-[10px] font-black text-slate-400 border-2 border-white shadow-sm flex-shrink-0">
                        +{order.attachments.length - 4}
                      </div>
                    )}
                 </div>
               )}

               {/* Action Buttons */}
               <div className="flex gap-3 pt-6 border-t border-slate-50">
                  <button onClick={() => onEdit(order.id!)} className="flex-1 py-4 bg-indigo-50 text-indigo-600 rounded-[1.25rem] font-black uppercase tracking-widest text-[10px] hover:bg-indigo-600 hover:text-white transition-all shadow-sm hover:shadow-indigo-100/40">Modify Record</button>
                  <button onClick={() => handleDelete(order)} className="p-4 bg-rose-50 text-rose-500 rounded-[1.25rem] hover:bg-rose-500 hover:text-white transition-all border border-rose-100 group/del">
                    <svg className="w-5 h-5 group-hover/del:rotate-12 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                  </button>
               </div>
            </div>
          ))
        )}
      </div>

      {/* Premium Gallery Modal */}
      {galleryState && (
        <div className="fixed inset-0 z-[200] bg-black/98 backdrop-blur-2xl flex flex-col items-center justify-center p-4 animate-in fade-in duration-300" onClick={() => setGalleryState(null)}>
           <div className="relative w-full max-w-5xl flex flex-col items-center" onClick={e => e.stopPropagation()}>
              <div className="absolute -top-16 right-0">
                <button onClick={() => setGalleryState(null)} className="p-3 bg-white/10 text-white rounded-full hover:bg-rose-500 transition-colors border border-white/10">
                   <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
              </div>

              <img src={galleryState.images[galleryState.index]} className="max-w-full max-h-[80vh] object-contain rounded-3xl shadow-[0_0_100px_rgba(255,255,255,0.05)] animate-in zoom-in-95 duration-500" alt="Full size proof" />

              <div className="mt-10 flex gap-6 items-center">
                 <button onClick={() => setGalleryState({...galleryState, index: (galleryState.index - 1 + galleryState.images.length) % galleryState.images.length})} className="p-5 bg-white/5 text-white rounded-full border border-white/10 hover:bg-white/10 hover:scale-110 active:scale-95 transition-all">
                   <svg className="w-7 h-7" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M15 19l-7-7 7-7" /></svg>
                 </button>
                 <div className="px-8 py-3 bg-white/5 rounded-full border border-white/10 backdrop-blur-md">
                    <span className="text-[10px] font-black text-white uppercase tracking-widest">{galleryState.index + 1} / {galleryState.images.length}</span>
                 </div>
                 <button onClick={() => setGalleryState({...galleryState, index: (galleryState.index + 1) % galleryState.images.length})} className="p-5 bg-white/5 text-white rounded-full border border-white/10 hover:bg-white/10 hover:scale-110 active:scale-95 transition-all">
                   <svg className="w-7 h-7" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M9 5l7 7-7 7" /></svg>
                 </button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default OrdersList;

import React, { useState, useMemo, useEffect } from 'react';
import { db, Order, Shipment } from '../db';
import { useLiveQuery } from 'dexie-react-hooks';
import { StorageMode } from '../types';
import { getOrders, deleteOrder } from '../services/orderService';
import { getShipments } from '../services/shipmentService';
import { initSupabase } from '../services/syncService';

interface Props {
  mode: StorageMode;
  onEdit: (id: number) => void;
}

const STATUS_OPTIONS = ['Pending', 'Processing', 'Shipped', 'Delivered', 'Cancelled'];

const getStatusColor = (status: string) => {
  switch (status) {
    case 'Pending': return 'bg-amber-50 text-amber-600 border-amber-100';
    case 'Processing': return 'bg-blue-50 text-blue-600 border-blue-100';
    case 'Shipped': return 'bg-indigo-50 text-indigo-600 border-indigo-100';
    case 'Delivered': return 'bg-emerald-50 text-emerald-600 border-emerald-100';
    case 'Cancelled': return 'bg-rose-50 text-rose-600 border-rose-100';
    default: return 'bg-slate-50 text-slate-600 border-slate-100';
  }
};

const OrdersList: React.FC<Props> = ({ mode, onEdit }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCity, setFilterCity] = useState('');
  const [filterCustomer, setFilterCustomer] = useState('');
  const [filterMaterial, setFilterMaterial] = useState('');
  const [filterStatus, setFilterStatus] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [isFilterExpanded, setIsFilterExpanded] = useState(false);

  const [onlineOrders, setOnlineOrders] = useState<Order[]>([]);
  const [onlineShipments, setOnlineShipments] = useState<Shipment[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isRealtimeActive, setIsRealtimeActive] = useState(false);
  const [galleryState, setGalleryState] = useState<{ images: string[], index: number } | null>(null);

  const localOrders = useLiveQuery(() => 
    db.orders.reverse().sortBy('orderDate')
  );
  const localShipments = useLiveQuery(() => db.shipments.toArray());

  const fetchOnline = async () => {
    if (mode !== StorageMode.ONLINE) return;
    setIsLoading(true);
    try {
      const [ordersData, shipmentsData] = await Promise.all([
        getOrders(StorageMode.ONLINE),
        getShipments(StorageMode.ONLINE)
      ]);
      setOnlineOrders(ordersData);
      setOnlineShipments(shipmentsData);
    } catch (err) {
      console.error("Fetch Online Error:", err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (mode === StorageMode.ONLINE) {
      fetchOnline();
      const supabase = initSupabase();
      if (!supabase) return;

      const channel = supabase
        .channel('public:orders_list_realtime_v7')
        .on('postgres_changes' as any, { event: '*', table: 'orders', schema: 'public' }, () => fetchOnline())
        .on('postgres_changes' as any, { event: '*', table: 'shipments', schema: 'public' }, () => fetchOnline())
        .subscribe((status) => {
          setIsRealtimeActive(status === 'SUBSCRIBED');
        });

      return () => {
        supabase.removeChannel(channel);
        setIsRealtimeActive(false);
      };
    } else {
      setOnlineOrders([]);
      setOnlineShipments([]);
      setIsRealtimeActive(false);
    }
  }, [mode]);

  const activeOrders = mode === StorageMode.OFFLINE ? (localOrders || []) : onlineOrders;
  const activeShipments = mode === StorageMode.OFFLINE ? (localShipments || []) : onlineShipments;

  const bundledOrderUuids = useMemo(() => {
    const uuids = new Set<string>();
    activeShipments.forEach(s => {
      if (s.orderUuids && Array.isArray(s.orderUuids)) {
        s.orderUuids.forEach(u => uuids.add(u));
      }
    });
    return uuids;
  }, [activeShipments]);

  const availableOrders = useMemo(() => {
    return activeOrders.filter(o => !bundledOrderUuids.has(o.uuid));
  }, [activeOrders, bundledOrderUuids]);

  const cities = useMemo(() => Array.from(new Set(availableOrders.map(o => (o.city || '').trim()))).sort() as string[], [availableOrders]);
  const customers = useMemo(() => Array.from(new Set(availableOrders.map(o => (o.customer || '').trim()))).sort() as string[], [availableOrders]);
  const materials = useMemo(() => Array.from(new Set(availableOrders.map(o => (o.material || '').trim()))).sort() as string[], [availableOrders]);

  const filteredOrders = useMemo(() => {
    return availableOrders.filter(o => {
      const searchStr = searchTerm.toLowerCase().trim();
      const matchesSearch = !searchStr || 
        o.customer.toLowerCase().includes(searchStr) ||
        o.city.toLowerCase().includes(searchStr) ||
        o.material.toLowerCase().includes(searchStr) ||
        (o.lrNo && o.lrNo.toLowerCase().includes(searchStr)) ||
        (o.vehicleNo && o.vehicleNo.toLowerCase().includes(searchStr)) ||
        (o.orderNo && o.orderNo.toLowerCase().includes(searchStr));

      const matchesCity = !filterCity || o.city.trim() === filterCity;
      const matchesCustomer = !filterCustomer || o.customer.trim() === filterCustomer;
      const matchesMaterial = !filterMaterial || o.material.trim() === filterMaterial;
      const matchesStatus = !filterStatus || o.status === filterStatus;

      const orderDate = new Date(o.orderDate).setHours(0,0,0,0);
      const start = startDate ? new Date(startDate).setHours(0,0,0,0) : null;
      const end = endDate ? new Date(endDate).setHours(23,59,59,999) : null;

      const matchesStart = !start || orderDate >= start;
      const matchesEnd = !end || orderDate <= end;

      return matchesSearch && matchesCity && matchesCustomer && matchesMaterial && matchesStatus && matchesStart && matchesEnd;
    });
  }, [availableOrders, searchTerm, filterCity, filterCustomer, filterMaterial, filterStatus, startDate, endDate]);

  const summaryStats = useMemo(() => {
    return {
      count: filteredOrders.length,
      totalQty: filteredOrders.reduce((sum, o) => sum + (o.qty || 0), 0),
      uniqueCities: new Set(filteredOrders.map(o => o.city)).size
    };
  }, [filteredOrders]);

  const hasActiveFilters = filterCity || filterCustomer || filterMaterial || filterStatus || startDate || endDate;

  const handleDelete = async (order: Order) => {
    if (confirm(`Delete record for ${order.customer}?`)) {
      try {
        await deleteOrder(mode, order.id!, order.uuid);
        if (mode === StorageMode.ONLINE) fetchOnline(); 
      } catch (err: any) {
        alert("Delete failed: " + err.message);
      }
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-700">
      {mode === StorageMode.ONLINE && (
        <div className="flex justify-center -mt-2">
           <div className={`flex items-center gap-2 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border shadow-sm transition-all ${isRealtimeActive ? 'bg-blue-50 border-blue-100 text-blue-600' : 'bg-rose-50 border-rose-100 text-rose-600'}`}>
              <div className={`w-1.5 h-1.5 rounded-full ${isRealtimeActive ? 'bg-blue-600 animate-pulse' : 'bg-rose-500'}`}></div>
              {isRealtimeActive ? 'Supabase Live' : 'Connection Lost'}
           </div>
        </div>
      )}

      {/* Dynamic Summary Bar */}
      <div className="grid grid-cols-3 gap-2 md:gap-4 mb-2">
         <div className="bg-white/40 backdrop-blur-sm p-3 md:p-4 rounded-3xl border border-white/60 shadow-sm">
            <p className="text-[8px] md:text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1">Active View</p>
            <p className="text-sm md:text-lg font-black text-slate-900 leading-none">{summaryStats.count} <span className="text-[10px] text-slate-400 font-bold uppercase ml-1">Orders</span></p>
         </div>
         <div className="bg-white/40 backdrop-blur-sm p-3 md:p-4 rounded-3xl border border-white/60 shadow-sm">
            <p className="text-[8px] md:text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1">Total Qty</p>
            <p className="text-sm md:text-lg font-black text-indigo-600 leading-none">{summaryStats.totalQty.toLocaleString()}</p>
         </div>
         <div className="bg-white/40 backdrop-blur-sm p-3 md:p-4 rounded-3xl border border-white/60 shadow-sm">
            <p className="text-[8px] md:text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1">Coverage</p>
            <p className="text-sm md:text-lg font-black text-slate-900 leading-none">{summaryStats.uniqueCities} <span className="text-[10px] text-slate-400 font-bold uppercase ml-1">Cities</span></p>
         </div>
      </div>

      {/* Enhanced Glassmorphic Sticky Header */}
      <div className="bg-white/80 backdrop-blur-2xl p-4 md:p-6 rounded-[2.5rem] shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-slate-100 sticky top-[72px] md:top-[80px] z-30 space-y-4 transition-all hover:shadow-lg">
        <div className="flex flex-col md:flex-row gap-3 items-center">
          <div className="relative flex-1 w-full group">
            <span className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-indigo-600 transition-colors">
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
            </span>
            <input
              type="text"
              placeholder={`Search customers, orders, or vehicles...`}
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-14 pr-6 py-4 bg-slate-100/50 border-none rounded-2xl focus:ring-2 focus:ring-indigo-500/10 shadow-inner font-bold text-slate-900 placeholder:text-slate-300 transition-all text-sm"
            />
            {searchTerm && (
              <button onClick={() => setSearchTerm('')} className="absolute right-4 top-1/2 -translate-y-1/2 p-1.5 text-slate-300 hover:text-rose-500 transition-colors">
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            )}
          </div>
          <div className="flex gap-2 w-full md:w-auto">
            <button 
              onClick={() => setIsFilterExpanded(!isFilterExpanded)}
              className={`flex-1 md:flex-none px-6 py-4 rounded-2xl font-black text-[10px] md:text-xs uppercase tracking-widest flex items-center justify-center gap-2 transition-all border ${isFilterExpanded ? 'bg-indigo-600 text-white border-indigo-600 shadow-xl shadow-indigo-100' : 'bg-white text-slate-500 border-slate-100 hover:bg-slate-50'}`}
            >
              <svg className={`w-4 h-4 transition-transform duration-500 ${isFilterExpanded ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M19 9l-7 7-7-7" /></svg>
              Filters {hasActiveFilters && <span className="w-2 h-2 rounded-full bg-rose-500 shadow-[0_0_8px_rgba(244,63,94,0.6)] animate-pulse"></span>}
            </button>
            {mode === StorageMode.ONLINE && (
              <button onClick={fetchOnline} disabled={isLoading} className="p-4 bg-blue-50 text-blue-600 rounded-2xl hover:bg-blue-100 transition-colors border border-blue-100 group">
                <svg className={`w-5 h-5 ${isLoading ? 'animate-spin' : 'group-active:rotate-180 transition-transform duration-500'}`} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
              </button>
            )}
          </div>
        </div>

        {isFilterExpanded && (
          <div className="grid grid-cols-2 lg:grid-cols-6 gap-4 pt-4 border-t border-slate-50 animate-in slide-in-from-top-4 duration-500">
            <div className="flex flex-col gap-1.5">
               <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Client</label>
               <select value={filterCustomer} onChange={(e) => setFilterCustomer(e.target.value)} className="px-4 py-2.5 bg-slate-50 border-none rounded-xl text-[11px] font-bold outline-none shadow-sm focus:bg-white focus:ring-1 focus:ring-indigo-100/50">
                  <option value="">All Clients</option>
                  {customers.map(c => <option key={c} value={c}>{c}</option>)}
               </select>
            </div>
            <div className="flex flex-col gap-1.5">
               <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Status</label>
               <select value={filterStatus} onChange={(e) => setFilterStatus(e.target.value)} className="px-4 py-2.5 bg-slate-50 border-none rounded-xl text-[11px] font-bold outline-none shadow-sm focus:bg-white focus:ring-1 focus:ring-indigo-100/50">
                  <option value="">All Status</option>
                  {STATUS_OPTIONS.map(s => <option key={s} value={s}>{s}</option>)}
               </select>
            </div>
            <div className="flex flex-col gap-1.5">
               <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Destination</label>
               <select value={filterCity} onChange={(e) => setFilterCity(e.target.value)} className="px-4 py-2.5 bg-slate-50 border-none rounded-xl text-[11px] font-bold outline-none shadow-sm focus:bg-white focus:ring-1 focus:ring-indigo-100/50">
                  <option value="">All Cities</option>
                  {cities.map(c => <option key={c} value={c}>{c}</option>)}
               </select>
            </div>
            <div className="flex flex-col gap-1.5">
               <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Material</label>
               <select value={filterMaterial} onChange={(e) => setFilterMaterial(e.target.value)} className="px-4 py-2.5 bg-slate-50 border-none rounded-xl text-[11px] font-bold outline-none shadow-sm focus:bg-white focus:ring-1 focus:ring-indigo-100/50">
                  <option value="">All Items</option>
