export default Backup;

import { createClient, SupabaseClient } from '@supabase/supabase-js';
import { db, Order, Shipment } from '../db';

let supabase: SupabaseClient | null = null;

const SYNC_CONFIG_KEY = 'order_tracker_supabase_config';

interface SyncConfig {
  url: string;
  publishableKey: string;
}

export const getSyncConfig = (): SyncConfig | null => {
  const data = localStorage.getItem(SYNC_CONFIG_KEY);
  return data ? JSON.parse(data) : null;
};

export const saveSyncConfig = (config: SyncConfig) => {
  localStorage.setItem(SYNC_CONFIG_KEY, JSON.stringify(config));
  supabase = createClient(config.url, config.publishableKey);
};

export const initSupabase = () => {
  const config = getSyncConfig();
  if (config && !supabase) {
    try {
      supabase = createClient(config.url, config.publishableKey);
    } catch (e) {
      console.error("Supabase Init Failed", e);
      return null;
    }
  }
  return supabase;
};

export const clearSupabaseData = async () => {
  const client = initSupabase();
  if (!client) throw new Error("Supabase not configured.");

  const { error: err1 } = await client.from('orders').delete().neq('uuid', '00000000-0000-0000-0000-000000000000'); 
  const { error: err2 } = await client.from('shipments').delete().neq('uuid', '00000000-0000-0000-0000-000000000000'); 

  if (err1) throw err1;
  if (err2) throw err2;
};

/**
 * Normalizes Order CSV data to Supabase schema with LWW conflict resolution.
 */
export const importCsvToSupabase = async (data: any[]) => {
  const client = initSupabase();
  if (!client) throw new Error("Cloud Datastore not configured.");

  const nowIso = new Date().toISOString();

  const payload = data.map(o => {
    // Normalizes any date value to a local YYYY-MM-DD string for database storage
    const parseToIsoDate = (val: any) => {
      if (!val) return null;
      const d = new Date(isNaN(val) ? val : Number(val));
      if (!d.getTime()) return null;
      // Extract local date parts to prevent shift during UTC conversion
      const year = d.getFullYear();
      const month = String(d.getMonth() + 1).padStart(2, '0');
      const day = String(d.getDate()).padStart(2, '0');
      return `${year}-${month}-${day}`;
    };

    const parseToIsoTimestamp = (val: any) => {
      if (!val) return null;
      const d = new Date(isNaN(val) ? val : Number(val));
      return d.getTime() ? d.toISOString() : null;
    };

    let finalAttachments = [];
    if (o.attachments) {
      if (Array.isArray(o.attachments)) {
        finalAttachments = o.attachments;
      } else if (typeof o.attachments === 'string') {
        try {
          const parsed = JSON.parse(o.attachments);
          if (Array.isArray(parsed)) finalAttachments = parsed;
        } catch (e) {
          finalAttachments = [o.attachments];
        }
      }
    }

    return {
      uuid: o.uuid || crypto.randomUUID(),
      order_no: String(o.orderNo || o.order_no || '').trim(),
      order_date: parseToIsoDate(o.orderDate || o.order_date || o.createdAt || o.created_at) || nowIso.split('T')[0],
      cust_code: String(o.custCode || o.cust_code || '').trim(),
      customer: String(o.customer || 'Unknown').trim(),
      city: String(o.city || 'Unknown').trim(),
      zip_code: String(o.zipCode || o.zip_code || '').trim(),
      material: String(o.material || 'N/A').trim(),
      qty: Number(o.qty || 0),
      status: o.status || 'Pending',
      note: o.note || '',
      attachments: finalAttachments,
      invoice_no: o.invoiceNo || o.invoice_no || '',
      invoice_date: parseToIsoDate(o.invoiceDate || o.invoice_date),
      vehicle_no: o.vehicleNo || o.vehicle_no || '',
      transporter: o.transporter || '',
      lr_no: o.lrNo || o.lr_no || '',
      created_at: parseToIsoTimestamp(o.createdAt || o.created_at) || nowIso,
      updated_at: nowIso
    };
  });

  const { error } = await client.from('orders').upsert(payload, { onConflict: 'uuid' });
  if (error) throw new Error(error.message);
  return payload.length;
};

/**
 * importShipmentsCsvToSupabase handles the shipment table synchronization.
 */
export const importShipmentsCsvToSupabase = async (data: any[]) => {
  const client = initSupabase();
  if (!client) throw new Error("Cloud Datastore not configured.");

  const nowIso = new Date().toISOString();

  const payload = data.map(s => {
    const parseToIso = (val: any) => {
      if (!val) return null;
      const d = new Date(isNaN(val) ? val : Number(val));
      return d.getTime() ? d.toISOString() : null;
    };

    // Normalize order_uuids array
    let orderUuids = [];
    const rawUuids = s.orderUuids || s.order_uuids;
    if (Array.isArray(rawUuids)) {
      orderUuids = rawUuids;
    } else if (typeof rawUuids === 'string') {
      try {
        const parsed = JSON.parse(rawUuids);
        if (Array.isArray(parsed)) orderUuids = parsed;
      } catch {
        orderUuids = rawUuids.split(';').map(u => u.trim()).filter(Boolean);
      }
    }

    // Normalize attachments array
    let attachments = [];
    const rawAttachments = s.attachments;
    if (Array.isArray(rawAttachments)) {
      attachments = rawAttachments;
    } else if (typeof rawAttachments === 'string') {
      try {
        const parsed = JSON.parse(rawAttachments);
        if (Array.isArray(parsed)) attachments = parsed;
      } catch {
        attachments = [rawAttachments];
      }
    }

    return {
      uuid: s.uuid || crypto.randomUUID(),
      reference: String(s.reference || '').trim(),
      order_uuids: orderUuids,
      attachments: attachments,
      dispatch_date: parseToIso(s.dispatchDate || s.dispatch_date) || nowIso,
      note: s.note || '',
      created_at: parseToIso(s.createdAt || s.created_at) || nowIso,
      updated_at: nowIso
    };
  });

  const { error } = await client.from('shipments').upsert(payload, { onConflict: 'uuid' });
  if (error) throw new Error(error.message);
  return payload.length;
};

// We use a global script for PapaParse in index.html to avoid import issues,
// but we'll use window.Papa in our functions.
declare const Papa: any;

const formatDateToCustom = (timestamp: any): string => {
  if (!timestamp) return '';
  const d = new Date(isNaN(timestamp) ? timestamp : Number(timestamp));
  if (isNaN(d.getTime())) return String(timestamp);

  const day = String(d.getDate()).padStart(2, '0');
  const month = String(d.getMonth() + 1).padStart(2, '0');
  const year = d.getFullYear();
  return `${day}.${month}.${year}`;
};

export const exportToCSV = (data: any[], filename: string) => {
  if (typeof Papa === 'undefined') {
    alert("CSV Library (PapaParse) is not available. Please check your internet connection.");
    return;
  }

  // Pre-process: Format dates to dd.mm.yyyy and stringify nested arrays
  const processedData = data.map(item => {
    const newItem = { ...item };

    // Format known date fields
    const dateFields = ['orderDate', 'invoiceDate', 'dispatchDate', 'createdAt', 'updatedAt', 'order_date', 'invoice_date', 'dispatch_date', 'created_at', 'updated_at'];
    dateFields.forEach(field => {
      if (newItem[field]) {
        newItem[field] = formatDateToCustom(newItem[field]);
      }
    });

    if (newItem.attachments && Array.isArray(newItem.attachments)) {
      newItem.attachments = JSON.stringify(newItem.attachments);
    }
    if (newItem.orderUuids && Array.isArray(newItem.orderUuids)) {
      newItem.orderUuids = JSON.stringify(newItem.orderUuids);
    }

    // Remove internal IDs for cleaner backup if needed, but keeping for LWW
    return newItem;
  });

  try {
    const csv = Papa.unparse(processedData);
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);

    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', filename);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);

    setTimeout(() => URL.revokeObjectURL(url), 100);
  } catch (error) {
    console.error("Export error:", error);
    alert("Error generating CSV.");
  }
};

export const parseCSV = (file: File): Promise<any[]> => {
  return new Promise((resolve, reject) => {
    if (typeof Papa === 'undefined') {
      reject(new Error("PapaParse not loaded"));
      return;
    }
    Papa.parse(file, {
      header: true,
      dynamicTyping: true,
      skipEmptyLines: true,
      complete: (results: any) => resolve(results.data),
      error: (error: any) => reject(error)
    });
  });
};

import React, { useState, useEffect } from 'react';
import { db, Order, Shipment } from '../db';
import { exportToCSV, parseCSV } from '../services/csvService';
import { saveSyncConfig, getSyncConfig, clearSupabaseData, importCsvToSupabase, importShipmentsCsvToSupabase, initSupabase } from '../services/syncService';
import { getOrders } from '../services/orderService';
import { getShipments } from '../services/shipmentService';
import { StorageMode } from '../types';

const Backup: React.FC = () => {
  const [importingLocal, setImportingLocal] = useState(false);
  const [importingCloudOrders, setImportingCloudOrders] = useState(false);
  const [importingCloudShipments, setImportingCloudShipments] = useState(false);
  const [exportingLocal, setExportingLocal] = useState(false);
  const [exportingCloud, setExportingCloud] = useState(false);
  const [clearingCloud, setClearingCloud] = useState(false);
  const [clearingLocal, setClearingLocal] = useState(false);

  const [cloudConfig, setCloudConfig] = useState({
    url: '',
    publishableKey: ''
  });

  useEffect(() => {
    const config = getSyncConfig();
    if (config) setCloudConfig(config);
  }, []);

  const handleSaveConfig = () => {
    if (!cloudConfig.url || !cloudConfig.publishableKey) {
      alert("Missing Information: Both Supabase URL and Key are required.");
      return;
    }
    saveSyncConfig(cloudConfig);
    alert("Cloud Credentials Updated.");
  };

  const handleExportLocal = async (type: 'orders' | 'shipments') => {
    setExportingLocal(true);
    try {
      const data = type === 'orders' ? await db.orders.toArray() : await db.shipments.toArray();
      if (data.length === 0) {
        alert(`${type} database is empty.`);
        return;
      }
      exportToCSV(data, `local_${type}_backup_${new Date().toISOString().split('T')[0]}.csv`);
    } catch (err) {
      alert("CSV Export failed.");
    } finally {
      setExportingLocal(false);
    }
  };

  const handleExportCloud = async (type: 'orders' | 'shipments') => {
    const client = initSupabase();
    if (!client) {
      alert("Please configure Cloud credentials first.");
      return;
    }
    setExportingCloud(true);
    try {
      const data = type === 'orders' ? await getOrders(StorageMode.ONLINE) : await getShipments(StorageMode.ONLINE);
      if (data.length === 0) {
        alert(`No ${type} found in the cloud database.`);
        return;
      }
      exportToCSV(data, `cloud_${type}_export_${new Date().toISOString().split('T')[0]}.csv`);
    } catch (err: any) {
      alert(`Cloud Export failed: ${err.message}`);
    } finally {
      setExportingCloud(false);
    }
  };

  // Helper to parse dd.mm.yyyy or standard date strings into Local Noon timestamp
  const parseDateToNoonTimestamp = (val: any): number | null => {
    if (!val) return null;
    let d: Date;

    // Check if it's a string in dd.mm.yyyy format
    if (typeof val === 'string' && val.includes('.')) {
      const parts = val.split('.');
      if (parts.length === 3) {
        // Assume DD.MM.YYYY
        d = new Date(Number(parts[2]), Number(parts[1]) - 1, Number(parts[0]), 12, 0, 0);
      } else {
        d = new Date(val);
      }
    } else {
      d = new Date(isNaN(val) ? val : Number(val));
    }

    if (isNaN(d.getTime())) return null;

    // Always force to Noon local time to avoid timezone shifts
    d.setHours(12, 0, 0, 0);
    return d.getTime();
  };

  const handleImportLocal = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setImportingLocal(true);
    try {
      const data = await parseCSV(file);
      if (!Array.isArray(data)) throw new Error("Invalid CSV format.");

      let count = 0;
      for (const item of data) {
        const isShipment = !!(item.orderUuids || item.order_uuids || item.reference);
        const targetTable = isShipment ? db.shipments : db.orders;

        if (!item.uuid) item.uuid = crypto.randomUUID();

        // Handle Order Date
        const dateKey = item.orderDate !== undefined ? 'orderDate' : 
                        (item.order_date !== undefined ? 'order_date' : 
                        (item.Date !== undefined ? 'Date' : 'date'));

        const timestamp = parseDateToNoonTimestamp(item[dateKey]);
        if (timestamp) {
          item.orderDate = timestamp;
          if (dateKey !== 'orderDate') delete item[dateKey];
        }

        // Handle Invoice Date
        if (item.invoiceDate || item.invoice_date) {
          const invTs = parseDateToNoonTimestamp(item.invoiceDate || item.invoice_date);
          if (invTs) item.invoiceDate = invTs;
        }

        // Handle Dispatch Date (for shipments)
        if (item.dispatchDate || item.dispatch_date) {
          const dispTs = parseDateToNoonTimestamp(item.dispatchDate || item.dispatch_date);
          if (dispTs) item.dispatchDate = dispTs;
        }

        if (typeof item.attachments === 'string' && item.attachments.startsWith('[')) {
          try { item.attachments = JSON.parse(item.attachments); } catch { item.attachments = []; }
        }

        if (isShipment && typeof (item.orderUuids || item.order_uuids) === 'string') {
           const raw = item.orderUuids || item.order_uuids;
           try { item.orderUuids = JSON.parse(raw); } catch { item.orderUuids = raw.split(';').map((u: string) => u.trim()); }
        }

        const existing = await targetTable.where('uuid').equals(item.uuid).first();
        if (existing) {
          await targetTable.update((existing as any).id!, { ...item, updatedAt: Date.now() });
        } else {
          await targetTable.add({ ...item, createdAt: item.createdAt || Date.now(), updatedAt: Date.now() } as any);
        }
        count++;
      }
      alert(`Local Import Success: Merged ${count} records.`);
    } catch (err: any) {
      alert(`Import Error: ${err.message}`);
    } finally {
      setImportingLocal(false);
      if (e.target) e.target.value = '';
    }
  };

  const handleImportToCloud = async (e: React.ChangeEvent<HTMLInputElement>, type: 'orders' | 'shipments') => {
    const file = e.target.files?.[0];
    if (!file || !cloudConfig.url) {
      alert("Please configure Cloud credentials first.");
      return;
    }
    type === 'orders' ? setImportingCloudOrders(true) : setImportingCloudShipments(true);
    try {
      const data = await parseCSV(file);
      const count = type === 'orders' ? await importCsvToSupabase(data) : await importShipmentsCsvToSupabase(data);
      alert(`Cloud Push Success: ${count} ${type} synchronized to Supabase.`);
    } catch (err: any) {
      console.error(err);
      alert(`Cloud Push Failed: ${err.message}`);
    } finally {
      type === 'orders' ? setImportingCloudOrders(false) : setImportingCloudShipments(false);
      if (e.target) e.target.value = '';
    }
  };

  const handleWipeCloud = async () => {
    if (!confirm("WARNING: This will permanently DELETE all records from Supabase. Offline data remains safe. Proceed?")) return;
    setClearingCloud(true);
    try {
      await clearSupabaseData();
      alert("Remote database successfully cleared.");
    } catch (err: any) {
      alert(`Reset Failed: ${err.message}`);
    } finally {
      setClearingCloud(false);
    }
  };

  const handleWipeLocal = async () => {
    if (!confirm("WARNING: This will permanently DELETE all local data. Proceed?")) return;
    setClearingLocal(true);
    try {
      await Promise.all([
        db.orders.clear(),
        db.shipments.clear(),
        db.customersMaster.clear(),
        db.citiesMaster.clear(),
        db.materialsMaster.clear()
      ]);
      alert("Local device storage cleared.");
    } catch (err: any) {
      alert(`Wipe Failed: ${err.message}`);
    } finally {
      setClearingLocal(false);
    }
  };

  return (
